/**
 * k6 Stress Test - Full Service Lifecycle
 *
 * 50 VUs, each executing 1 complete client-worker service lifecycle.
 * Reads manifest.json (generated by setup.ts) for credentials and IDs.
 *
 * Usage: k6 run test/stress/k6-lifecycle.js
 */

import { sleep } from 'k6';
import { Trend, Rate, Counter } from 'k6/metrics';
import { SharedArray } from 'k6/data';

import {
  supabaseSignIn,
  supabaseSelect,
  supabaseInsert,
  supabaseInsertAdmin,
  supabasePatchAdmin,
  supabaseRpc,
  supabaseRpcAdmin,
} from './k6-helpers.js';

// ─── Load manifest (shared across all VUs, loaded once) ────────────────────

const manifest = JSON.parse(open('./test/stress/results/manifest.json'));
const BASE_URL = manifest.supabaseUrl;
const ANON_KEY = manifest.supabaseAnonKey;
const SERVICE_KEY = manifest.supabaseServiceRoleKey;

const pairs = new SharedArray('pairs', function () {
  return manifest.pairs;
});

// ─── Custom Metrics ────────────────────────────────────────────────────────

const authDuration = new Trend('auth_duration', true);
const rechargeDuration = new Trend('recharge_duration', true);
const approvalDuration = new Trend('approval_duration', true);
const balanceRecalcDuration = new Trend('balance_recalc_duration', true);
const rpcHireDuration = new Trend('rpc_hire_duration', true);
const rpcCompleteDuration = new Trend('rpc_complete_duration', true);
const chatSendDuration = new Trend('chat_send_duration', true);

const errorRate = new Rate('errors');
const balanceErrors = new Rate('balance_errors');
const coldStartRate = new Rate('cold_starts');

const insufficientFunds = new Counter('insufficient_funds_errors');

// ─── k6 Options ────────────────────────────────────────────────────────────

export const options = {
  scenarios: {
    lifecycle: {
      executor: 'per-vu-iterations',
      vus: pairs.length, // 50
      iterations: 1,
      maxDuration: '5m',
    },
  },
  thresholds: {
    recharge_duration: ['p(95)<3000'],
    approval_duration: ['p(95)<3000'],
    balance_recalc_duration: ['p(95)<3000'],
    rpc_hire_duration: ['p(95)<5000'],
    rpc_complete_duration: ['p(95)<5000'],
    chat_send_duration: ['p(95)<2000'],
    errors: ['rate<0.05'],
    balance_errors: ['rate<0.01'],
    http_req_duration: ['p(99)<10000'],
  },
};

// ─── Constants ─────────────────────────────────────────────────────────────

const RECHARGE_AMOUNT = 2000000;
const COMMISSION_MULTIPLIER = 1.10; // 10% commission

// ─── Main test function (runs once per VU) ─────────────────────────────────

export default function () {
  const vuIndex = __VU - 1; // VU IDs start at 1
  if (vuIndex >= pairs.length) return; // safety guard

  const pair = pairs[vuIndex];
  const serviceId = pair.serviceId;
  const applicationId = pair.applicationId;
  const proposedPrice = pair.proposedPrice;
  const finalPrice = Math.round(proposedPrice * COMMISSION_MULTIPLIER);

  let clientJwt = null;
  let workerJwt = null;

  // ── Step 1: Auth client ──────────────────────────────────────────────

  let start = Date.now();
  const clientAuth = supabaseSignIn(BASE_URL, ANON_KEY, pair.client.email, pair.client.password);
  authDuration.add(Date.now() - start);

  if (!clientAuth) {
    errorRate.add(1);
    console.error(`VU${__VU}: Client auth failed`);
    return;
  }
  errorRate.add(0);
  clientJwt = clientAuth.access_token;
  coldStartRate.add(Date.now() - start > 2000 ? 1 : 0);

  sleep(Math.random() * 0.5);

  // ── Step 2: Auth worker ──────────────────────────────────────────────

  start = Date.now();
  const workerAuth = supabaseSignIn(BASE_URL, ANON_KEY, pair.worker.email, pair.worker.password);
  authDuration.add(Date.now() - start);

  if (!workerAuth) {
    errorRate.add(1);
    console.error(`VU${__VU}: Worker auth failed`);
    return;
  }
  errorRate.add(0);
  workerJwt = workerAuth.access_token;

  sleep(Math.random() * 0.5);

  // ── Step 3: Client creates pending recharge ──────────────────────────

  start = Date.now();
  const txn = supabaseInsert(BASE_URL, ANON_KEY, clientJwt, 'transactions', {
    user_id: pair.client.userId,
    type: 'recarga',
    amount: RECHARGE_AMOUNT,
    status: 'pendiente',
    payment_method: 'nequi',
    description: '[Stress Test] Recarga de saldo',
  });
  rechargeDuration.add(Date.now() - start);

  if (!txn || !txn.id) {
    errorRate.add(1);
    console.error(`VU${__VU}: Recharge insert failed`);
    return;
  }
  errorRate.add(0);

  sleep(Math.random() * 0.3);

  // ── Step 4: Admin approves recharge ──────────────────────────────────

  start = Date.now();
  const approved = supabasePatchAdmin(
    BASE_URL,
    SERVICE_KEY,
    'transactions',
    `id=eq.${txn.id}`,
    { status: 'completado' }
  );
  approvalDuration.add(Date.now() - start);

  if (!approved) {
    errorRate.add(1);
    console.error(`VU${__VU}: Recharge approval failed`);
    return;
  }
  errorRate.add(0);

  sleep(Math.random() * 0.3);

  // ── Step 5: Recalculate balance via RPC ──────────────────────────────

  start = Date.now();
  supabaseRpcAdmin(BASE_URL, SERVICE_KEY, 'update_user_balance_safe', {
    user_uuid: pair.client.userId,
  });
  balanceRecalcDuration.add(Date.now() - start);

  sleep(Math.random() * 0.3);

  // ── Step 6: Verify balance is correct ────────────────────────────────

  const profiles = supabaseSelect(
    BASE_URL,
    ANON_KEY,
    clientJwt,
    'user_profiles',
    `user_id=eq.${pair.client.userId}&select=balance`
  );

  if (!profiles || !profiles.length || profiles[0].balance < RECHARGE_AMOUNT) {
    balanceErrors.add(1);
    console.error(
      `VU${__VU}: Balance check failed. Expected >= ${RECHARGE_AMOUNT}, got: ${
        profiles?.[0]?.balance
      }`
    );
    // Don't return - try to continue and see if hiring fails
  } else {
    balanceErrors.add(0);
  }

  sleep(Math.random() * 0.5);

  // ── Step 7: Client hires worker (RPC) ────────────────────────────────

  start = Date.now();
  const hireResult = supabaseRpc(BASE_URL, ANON_KEY, clientJwt, 'escrow_service_select_worker', {
    service_uuid: serviceId,
    worker_uuid: pair.worker.userId,
    application_uuid: applicationId,
    final_price: finalPrice,
  });
  rpcHireDuration.add(Date.now() - start);

  if (!hireResult || !hireResult.success) {
    errorRate.add(1);
    const errMsg = hireResult?.error || JSON.stringify(hireResult);
    console.error(`VU${__VU}: Hire RPC failed: ${errMsg}`);
    if (errMsg && errMsg.includes('insuficiente')) {
      insufficientFunds.add(1);
    }
    return;
  }
  errorRate.add(0);

  const completionPin = hireResult.pin;

  sleep(Math.random() * 0.5);

  // ── Step 8: Get booking_id (needed for chat) ─────────────────────────

  const bookings = supabaseSelect(
    BASE_URL,
    ANON_KEY,
    clientJwt,
    'bookings',
    `service_id=eq.${serviceId}&select=id`
  );

  if (!bookings || !bookings.length) {
    errorRate.add(1);
    console.error(`VU${__VU}: No booking found after hiring`);
    return;
  }
  errorRate.add(0);

  const bookingId = bookings[0].id;

  // ── Step 9: Get completion PIN (verification / redundant) ────────────

  const escrows = supabaseSelect(
    BASE_URL,
    ANON_KEY,
    clientJwt,
    'escrow_transactions',
    `service_id=eq.${serviceId}&select=completion_pin`
  );

  const verifiedPin = escrows?.[0]?.completion_pin || completionPin;

  sleep(Math.random() * 0.3);

  // ── Step 10: Ensure chat exists ──────────────────────────────────────

  let chatId = null;

  const existingChats = supabaseSelect(
    BASE_URL,
    ANON_KEY,
    clientJwt,
    'chats',
    `booking_id=eq.${bookingId}&select=id`
  );

  if (existingChats && existingChats.length > 0) {
    chatId = existingChats[0].id;
  } else {
    // Create chat via service-role (RLS might block user insert)
    const newChat = supabaseInsertAdmin(BASE_URL, SERVICE_KEY, 'chats', {
      booking_id: bookingId,
      client_id: pair.client.userId,
      worker_id: pair.worker.userId,
    });
    if (newChat) {
      chatId = newChat.id;
    }
  }

  if (!chatId) {
    console.warn(`VU${__VU}: Chat creation failed, skipping messages`);
  }

  sleep(Math.random() * 0.3);

  // ── Step 11: Client sends 3 messages ─────────────────────────────────

  if (chatId) {
    for (let m = 1; m <= 3; m++) {
      start = Date.now();
      supabaseInsert(BASE_URL, ANON_KEY, clientJwt, 'chat_messages', {
        chat_id: chatId,
        sender_id: pair.client.userId,
        message: `[Stress Test] Client message ${m} from VU${__VU}`,
        message_type: 'text',
      });
      chatSendDuration.add(Date.now() - start);
      sleep(Math.random() * 0.2);
    }
  }

  // ── Step 12: Worker sends 3 messages ─────────────────────────────────

  if (chatId) {
    for (let m = 1; m <= 3; m++) {
      start = Date.now();
      supabaseInsert(BASE_URL, ANON_KEY, workerJwt, 'chat_messages', {
        chat_id: chatId,
        sender_id: pair.worker.userId,
        message: `[Stress Test] Worker message ${m} from VU${__VU}`,
        message_type: 'text',
      });
      chatSendDuration.add(Date.now() - start);
      sleep(Math.random() * 0.2);
    }
  }

  sleep(Math.random() * 0.5);

  // ── Step 13: Worker completes service with PIN (RPC) ─────────────────

  start = Date.now();
  const completeResult = supabaseRpc(
    BASE_URL,
    ANON_KEY,
    workerJwt,
    'complete_service_with_pin',
    {
      service_uuid: serviceId,
      worker_uuid: pair.worker.userId,
      pin_code: verifiedPin,
    }
  );
  rpcCompleteDuration.add(Date.now() - start);

  if (!completeResult || !completeResult.success) {
    errorRate.add(1);
    console.error(
      `VU${__VU}: Complete RPC failed: ${completeResult?.error || JSON.stringify(completeResult)}`
    );
    return;
  }
  errorRate.add(0);

  sleep(Math.random() * 0.3);

  // ── Step 14: Verify service is completed ─────────────────────────────

  const services = supabaseSelect(
    BASE_URL,
    ANON_KEY,
    clientJwt,
    'services',
    `id=eq.${serviceId}&select=status`
  );

  if (!services || !services.length || services[0].status !== 'completed') {
    errorRate.add(1);
    console.error(
      `VU${__VU}: Service not completed. Status: ${services?.[0]?.status}`
    );
  } else {
    errorRate.add(0);
  }

  // ── Step 15: Verify worker balance increased ─────────────────────────

  const workerProfiles = supabaseSelect(
    BASE_URL,
    ANON_KEY,
    workerJwt,
    'user_profiles',
    `user_id=eq.${pair.worker.userId}&select=balance`
  );

  if (!workerProfiles || !workerProfiles.length || workerProfiles[0].balance <= 0) {
    balanceErrors.add(1);
    console.error(
      `VU${__VU}: Worker balance not updated. Balance: ${workerProfiles?.[0]?.balance}`
    );
  } else {
    balanceErrors.add(0);
    console.log(
      `VU${__VU}: ✓ Complete! Worker balance: ${workerProfiles[0].balance}`
    );
  }
}
